{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "urn:tools:search:v2",
  "title": "search",
  "description": "Search the knowledge base for documents relevant to a query. Returns a list of results ranked by relevance.",
  "type": "object",
  "properties": {
    "query": {
      "type": "string",
      "description": "The search query. Use specific, factual language for best results.",
      "minLength": 3,
      "maxLength": 500
    },
    "max_results": {
      "type": "integer",
      "description": "Maximum number of results to return.",
      "minimum": 1,
      "maximum": 20,
      "default": 5
    },
    "filter_date_after": {
      "type": "string",
      "format": "date",
      "description": "Optional ISO 8601 date. Only return documents published after this date."
    }
  },
  "required": ["query"],
  "additionalProperties": false
}
